  1→import SwiftUI
  2→import AppKit
  3→
  4→class AppDelegate: NSObject, NSApplicationDelegate {
  5→    private var statusItem: NSStatusItem!
  6→    private var popover: NSPopover!
  7→    private let monitors = MonitorCoordinator.shared
  8→    private let settings = AppSettings.shared
  9→    private let historyStore = HistoryStore.shared
 10→    private var menuBarController: MenuBarController!
 11→    private var alertRulesEngine: AlertRulesEngine?
 12→    private var lowBatteryAlertTimer: Timer?
 13→    private var lowBatteryAlertShown = false
 14→    private var batteryAutomationTimer: Timer?
 15→    private var batterySettingsOpenedAt: Date?
 16→
 17→    func applicationDidFinishLaunching(_ notification: Notification) {
 18→        NSApp.setActivationPolicy(.accessory)
 19→        monitors.setPowerSaveMode(settings.powerSaveModeActive)
 20→
 21→        // Start monitoring
 22→        monitors.startAll()
 23→        historyStore.start(with: monitors)
 24→
 25→        // Create status item
 26→        statusItem = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)
 27→
 28→        if let button = statusItem.button {
 29→            button.action = #selector(handleStatusItemClick(_:))
 30→            button.target = self
 31→            button.sendAction(on: [.leftMouseUp, .rightMouseUp])
 32→        }
 33→
 34→        // Create and start menu bar controller
 35→        menuBarController = MenuBarController(statusItem: statusItem, monitors: monitors)
 36→        menuBarController.startUpdating()
 37→
 38→        startAlertRulesEngine()
 39→        startLowBatteryAlertMonitoring()
 40→        startBatteryAutomationMonitoring()
 41→
 42→        // Create popover
 43→        popover = NSPopover()
 44→        popover.contentSize = NSSize(width: 360, height: 520)
 45→        popover.behavior = .transient
 46→        popover.contentViewController = NSHostingController(
 47→            rootView: DashboardView(monitors: monitors, historyStore: historyStore)
 48→        )
 49→    }
 50→
 51→    func applicationWillTerminate(_ notification: Notification) {
 52→        alertRulesEngine?.stop()
 53→        alertRulesEngine = nil
 54→        lowBatteryAlertTimer?.invalidate()
 55→        lowBatteryAlertTimer = nil
 56→        batteryAutomationTimer?.invalidate()
 57→        batteryAutomationTimer = nil
 58→        historyStore.stop()
 59→        menuBarController.stopUpdating()
 60→        monitors.stopAll()
 61→    }
 62→
 63→    @objc private func handleStatusItemClick(_ sender: NSStatusBarButton) {
 64→        guard let event = NSApp.currentEvent else {
 65→            togglePopover()
 66→            return
 67→        }
 68→
 69→        switch event.type {
 70→        case .rightMouseUp:
 71→            popover.performClose(nil)
 72→            statusItem.menu = statusMenu()
 73→            sender.performClick(nil)
 74→            statusItem.menu = nil
 75→        default:
 76→            togglePopover()
 77→        }
 78→    }
 79→
 80→    @objc func togglePopover() {
 81→        guard let button = statusItem.button else { return }
 82→
 83→        if popover.isShown {
 84→            popover.performClose(nil)
 85→        } else {
 86→            popover.show(relativeTo: button.bounds, of: button, preferredEdge: .minY)
 87→        }
 88→    }
 89→
 90→    private func statusMenu() -> NSMenu {
 91→        let menu = NSMenu()
 92→        menu.addItem(
 93→            withTitle: "Open WhatTheLoad",
 94→            action: #selector(openDashboardFromMenu),
 95→            keyEquivalent: ""
 96→        )
 97→        menu.addItem(.separator())
 98→        menu.addItem(
 99→            withTitle: "Quit WhatTheLoad",
100→            action: #selector(quitApplication),
101→            keyEquivalent: "q"
102→        )
103→        menu.items.forEach { $0.target = self }
104→        return menu
105→    }
106→
107→    @objc private func openDashboardFromMenu() {
108→        if !popover.isShown {
109→            togglePopover()
110→        }
111→    }
112→
113→    @objc private func quitApplication() {
114→        NSApp.terminate(nil)
115→    }
116→
117→    private func startLowBatteryAlertMonitoring() {
118→        lowBatteryAlertTimer?.invalidate()
119→        lowBatteryAlertTimer = Timer.scheduledTimer(withTimeInterval: 15.0, repeats: true) { [weak self] _ in
120→            self?.checkLowBatteryAlert()
121→        }
122→        checkLowBatteryAlert()
123→    }
124→
125→    private func startAlertRulesEngine() {
126→        let engine = AlertRulesEngine(
127→            monitors: monitors,
128→            historyStore: historyStore,
129→            settings: settings
130→        )
131→        engine.onAlert = { [weak self] severity, title, message in
132→            guard title != "Low Battery" else { return }
133→            self?.showBlockingAlert(severity: severity, title: title, message: message)
134→        }
135→        engine.start()
136→        alertRulesEngine = engine
137→    }
138→
139→    private func startBatteryAutomationMonitoring() {
140→        batteryAutomationTimer?.invalidate()
141→        batteryAutomationTimer = Timer.scheduledTimer(withTimeInterval: 20.0, repeats: true) { [weak self] _ in
142→            self?.evaluateBatteryAutomation()
143→        }
144→        evaluateBatteryAutomation()
145→    }
146→
147→    private func checkLowBatteryAlert() {
148→        guard settings.lowBatteryAlertsEnabled else {
149→            lowBatteryAlertShown = false
150→            return
151→        }
152→
153→        guard let metrics = monitors.battery.current else { return }
154→
155→        let threshold = settings.lowBatteryAlertThreshold
156→        let isDischargingOnBattery = metrics.powerSource == .battery && !metrics.isCharging
157→
158→        if isDischargingOnBattery && metrics.chargePercent <= threshold {
159→            guard !lowBatteryAlertShown else { return }
160→            lowBatteryAlertShown = true
161→            showLowBatteryAlert(metrics: metrics, threshold: threshold)
162→            return
163→        }
164→
165→        let hasRecovered = metrics.isCharging || metrics.powerSource != .battery || metrics.chargePercent >= (threshold + 5)
166→        if hasRecovered {
167→            lowBatteryAlertShown = false
168→        }
169→    }
170→
171→    private func evaluateBatteryAutomation() {
172→        guard settings.batteryAutomationEnabled else {
173→            if settings.powerSaveModeActive {
174→                setPowerSaveMode(false, reason: "Low battery automation disabled.")
175→            }
176→            return
177→        }
178→
179→        guard let metrics = monitors.battery.current else { return }
180→        let threshold = settings.batteryAutomationThreshold
181→
182→        let shouldEnable = metrics.powerSource == .battery &&
183→            !metrics.isCharging &&
184→            metrics.chargePercent <= threshold
185→        let shouldDisable = metrics.isCharging ||
186→            metrics.powerSource != .battery ||
187→            metrics.chargePercent >= (threshold + 5)
188→
189→        if shouldEnable && !settings.powerSaveModeActive {
190→            setPowerSaveMode(true, reason: String(format: "Battery reached %.0f%%.", metrics.chargePercent))
191→            if settings.batteryAutomationAutoOpenSettings {
192→                openBatterySettingsIfNeeded()
193→            }
194→        } else if shouldDisable && settings.powerSaveModeActive {
195→            setPowerSaveMode(false, reason: "Battery state recovered.")
196→        }
197→    }
198→
199→    private func setPowerSaveMode(_ enabled: Bool, reason: String) {
200→        settings.powerSaveModeActive = enabled
201→        monitors.setPowerSaveMode(enabled)
202→        historyStore.recordEvent(TimelineEvent(
203→            severity: .info,
204→            category: .battery,
205→            title: enabled ? "Power Save Mode Enabled" : "Power Save Mode Disabled",
206→            message: reason
207→        ))
208→    }
209→
210→    private func openBatterySettingsIfNeeded() {
211→        let now = Date()
212→        if let lastOpened = batterySettingsOpenedAt, now.timeIntervalSince(lastOpened) < 1800 {
213→            return
214→        }
215→        batterySettingsOpenedAt = now
216→
217→        let urls = [
218→            "x-apple.systempreferences:com.apple.preference.battery",
219→            "x-apple.systempreferences:com.apple.Battery-Settings.extension"
220→        ]
221→
222→        for rawURL in urls {
223→            guard let url = URL(string: rawURL) else { continue }
224→            if NSWorkspace.shared.open(url) {
225→                return
226→            }
227→        }
228→    }
229→
230→    private func showLowBatteryAlert(metrics: BatteryMetrics, threshold: Double) {
231→        let levelText = String(format: "%.0f", metrics.chargePercent)
232→        let thresholdText = String(format: "%.0f", threshold)
233→
234→        var details = "Battery level is \(levelText)% (threshold \(thresholdText)%)."
235→        if let remaining = metrics.timeRemaining {
236→            details += "\nEstimated time remaining: \(formatRemainingTime(remaining))."
237→        }
238→        details += "\nPlug in your charger soon."
239→
240→        NSApp.activate(ignoringOtherApps: true)
241→
242→        let alert = NSAlert()
243→        alert.alertStyle = .warning
244→        alert.messageText = "Low Battery"
245→        alert.informativeText = details
246→        alert.addButton(withTitle: "Dismiss")
247→        alert.runModal()
248→    }
249→
250→    private func showBlockingAlert(severity: TimelineSeverity, title: String, message: String) {
251→        DispatchQueue.main.async {
252→            NSApp.activate(ignoringOtherApps: true)
253→
254→            let alert = NSAlert()
255→            alert.alertStyle = (severity == .critical) ? .critical : .warning
256→            alert.messageText = title
257→            alert.informativeText = message
258→            alert.addButton(withTitle: "Dismiss")
259→            alert.runModal()
260→        }
261→    }
262→
263→    private func formatRemainingTime(_ seconds: TimeInterval) -> String {
264→        let totalMinutes = max(0, Int(seconds / 60))
265→        let hours = totalMinutes / 60
266→        let minutes = totalMinutes % 60
267→
268→        if hours > 0 {
269→            return "\(hours)h \(minutes)m"
270→        }
271→        return "\(minutes)m"
272→    }
273→}
