  1→import SwiftUI
  2→import AppKit
  3→
  4→struct ProcessesSectionView: View {
  5→    let monitor: ProcessMonitor
  6→
  7→    @State private var sortColumn: SortColumn = .cpu
  8→    @State private var searchText = ""
  9→    @State private var selectedProcessID: Int32?
 10→    @State private var inspectorSnapshot: ProcessInspectorSnapshot?
 11→    @State private var isInspectingSelectedProcess = false
 12→    @State private var pendingSignalAction: PendingSignalAction?
 13→    @State private var resolvedExecutablePaths: [Int32: String] = [:]
 14→
 15→    enum SortColumn {
 16→        case name, pid, cpu, memory
 17→    }
 18→
 19→    var body: some View {
 20→        VStack(alignment: .leading, spacing: 12) {
 21→            Text("PROCESSES")
 22→                .font(.system(size: 11, weight: .medium, design: .monospaced))
 23→                .foregroundColor(Color.wtlSecondary)
 24→                .tracking(0.5)
 25→
 26→            HStack {
 27→                Image(systemName: "magnifyingglass")
 28→                    .foregroundColor(.secondary)
 29→                    .font(.system(size: 12))
 30→
 31→                TextField("Search processes...", text: $searchText)
 32→                    .textFieldStyle(.plain)
 33→                    .font(.system(size: 11, design: .monospaced))
 34→            }
 35→            .padding(8)
 36→            .background(Color.wtlCard)
 37→            .cornerRadius(6)
 38→
 39→            HStack(spacing: 8) {
 40→                sortableHeader("Name", width: 118, column: .name, alignment: .leading)
 41→                sortableHeader("PID", width: 44, column: .pid, alignment: .leading)
 42→                sortableHeader("CPU %", width: 54, column: .cpu, alignment: .trailing)
 43→                sortableHeader("Memory", width: 66, column: .memory, alignment: .trailing)
 44→            }
 45→            .font(.system(size: 9, weight: .semibold, design: .monospaced))
 46→            .foregroundColor(Color.wtlTertiary)
 47→            .padding(.horizontal, 8)
 48→
 49→            Divider()
 50→
 51→            if let current = monitor.current {
 52→                ScrollView {
 53→                    ForEach(filteredProcesses(current.processes), id: \.id) { process in
 54→                        ProcessRow(process: process, isSelected: process.id == selectedProcessID)
 55→                            .contentShape(Rectangle())
 56→                            .onTapGesture {
 57→                                selectedProcessID = process.id
 58→                                inspectProcess(process)
 59→                            }
 60→                            .contextMenu {
 61→                                Button("Reveal in Finder") {
 62→                                    revealProcessInFinder(process)
 63→                                }
 64→                                Divider()
 65→                                Button("Quit") {
 66→                                    scheduleSignalAction(for: process, signal: SIGTERM)
 67→                                }
 68→                                Button("Force Quit") {
 69→                                    scheduleSignalAction(for: process, signal: SIGKILL)
 70→                                }
 71→                            }
 72→                    }
 73→                }
 74→                .frame(height: 210)
 75→
 76→                detailPanel(for: current)
 77→            }
 78→        }
 79→        .onChange(of: monitor.current?.timestamp) { _, _ in
 80→            refreshSelectionIfNeeded()
 81→        }
 82→        .alert(item: $pendingSignalAction) { action in
 83→            Alert(
 84→                title: Text(action.title),
 85→                message: Text(action.message),
 86→                primaryButton: .destructive(Text(action.confirmTitle)) {
 87→                    kill(action.process.id, action.signal)
 88→                },
 89→                secondaryButton: .cancel()
 90→            )
 91→        }
 92→    }
 93→
 94→    private func sortableHeader(_ title: String, width: CGFloat, column: SortColumn, alignment: Alignment) -> some View {
 95→        Button {
 96→            sortColumn = column
 97→        } label: {
 98→            HStack(spacing: 2) {
 99→                Text(title)
100→                if sortColumn == column {
101→                    Image(systemName: "arrowtriangle.down.fill")
102→                        .font(.system(size: 7))
103→                }
104→            }
105→            .frame(width: width, alignment: alignment)
106→        }
107→        .buttonStyle(.plain)
108→        .foregroundColor(sortColumn == column ? Color.wtlSecondary : Color.wtlTertiary)
109→    }
110→
111→    @ViewBuilder
112→    private func detailPanel(for metrics: ProcessMetrics) -> some View {
113→        let selected = metrics.processes.first { $0.id == selectedProcessID }
114→
115→        VStack(alignment: .leading, spacing: 10) {
116→            Text("PROCESS DETAILS")
117→                .font(.system(size: 9, weight: .medium, design: .monospaced))
118→                .foregroundColor(Color.wtlTertiary)
119→                .tracking(0.5)
120→
121→            if let selected {
122→                HStack {
123→                    Text(selected.name)
124→                        .font(.system(size: 12, weight: .semibold))
125→                        .foregroundColor(.primary)
126→                        .lineLimit(1)
127→
128→                    Spacer()
129→
130→                    Text("PID \(selected.id)")
131→                        .font(.system(size: 10, design: .monospaced))
132→                        .foregroundColor(Color.wtlSecondary)
133→                }
134→
135→                Text(abbreviatedPath(executablePath(for: selected)))
136→                    .font(.system(size: 9, design: .monospaced))
137→                    .foregroundColor(Color.wtlTertiary)
138→                    .lineLimit(2)
139→
140→                HStack(spacing: 10) {
141→                    VStack(alignment: .leading, spacing: 4) {
142→                        Text("CPU TREND")
143→                            .font(.system(size: 9, weight: .medium, design: .monospaced))
144→                            .foregroundColor(Color.wtlTertiary)
145→                        SparklineView(data: cpuTrend(for: selected.id), color: .orange, height: 34)
146→                    }
147→
148→                    VStack(alignment: .leading, spacing: 4) {
149→                        Text("MEM TREND")
150→                            .font(.system(size: 9, weight: .medium, design: .monospaced))
151→                            .foregroundColor(Color.wtlTertiary)
152→                        SparklineView(data: memoryTrend(for: selected.id), color: .blue, height: 34)
153→                    }
154→                }
155→
156→                HStack(spacing: 14) {
157→                    StatInline(label: "CPU", value: String(format: "%.1f%%", selected.cpuUsage))
158→                    StatInline(label: "Memory", value: formatBytes(selected.memoryUsage))
159→                    StatInline(label: "Open Files", value: inspectorValue { "\($0.openFiles)" })
160→                    StatInline(label: "Sockets", value: inspectorValue { "\($0.sockets)" })
161→                }
162→
163→                HStack(spacing: 8) {
164→                    Button("Reveal") {
165→                        revealProcessInFinder(selected)
166→                    }
167→                    .buttonStyle(.bordered)
168→                    .controlSize(.small)
169→
170→                    Button("Quit") {
171→                        scheduleSignalAction(for: selected, signal: SIGTERM)
172→                    }
173→                    .buttonStyle(.bordered)
174→                    .controlSize(.small)
175→
176→                    Button("Force Quit", role: .destructive) {
177→                        scheduleSignalAction(for: selected, signal: SIGKILL)
178→                    }
179→                    .buttonStyle(.bordered)
180→                    .controlSize(.small)
181→
182→                    Spacer()
183→
184→                    if isInspectingSelectedProcess {
185→                        ProgressView()
186→                            .controlSize(.small)
187→                    }
188→                }
189→            } else {
190→                Text("Select a process to inspect path, open files, and socket usage.")
191→                    .font(.system(size: 11))
192→                    .foregroundColor(Color.wtlSecondary)
193→            }
194→        }
195→        .padding(10)
196→        .background(Color.wtlCard)
197→        .cornerRadius(8)
198→    }
199→
200→    private func filteredProcesses(_ processes: [ProcessDetails]) -> [ProcessDetails] {
201→        let filtered = searchText.isEmpty ? processes : processes.filter {
202→            $0.name.localizedCaseInsensitiveContains(searchText)
203→        }
204→
205→        return filtered.sorted { p1, p2 in
206→            switch sortColumn {
207→            case .name: return p1.name.localizedCaseInsensitiveCompare(p2.name) == .orderedAscending
208→            case .pid: return p1.id < p2.id
209→            case .cpu: return p1.cpuUsage > p2.cpuUsage
210→            case .memory: return p1.memoryUsage > p2.memoryUsage
211→            }
212→        }
213→    }
214→
215→    private func cpuTrend(for pid: Int32) -> [Double] {
216→        monitor.history.map { sample in
217→            sample.processes.first(where: { $0.id == pid })?.cpuUsage ?? 0
218→        }
219→    }
220→
221→    private func memoryTrend(for pid: Int32) -> [Double] {
222→        monitor.history.map { sample in
223→            Double(sample.processes.first(where: { $0.id == pid })?.memoryUsage ?? 0) / 1_048_576
224→        }
225→    }
226→
227→    private func inspectProcess(_ process: ProcessDetails) {
228→        isInspectingSelectedProcess = true
229→        inspectorSnapshot = nil
230→
231→        let pid = process.id
232→        DispatchQueue.global(qos: .utility).async {
233→            let output = runCommand("/usr/sbin/lsof", arguments: ["-n", "-P", "-p", "\(pid)"]) ?? ""
234→            let lines = output.split(whereSeparator: \.isNewline)
235→            let rows = lines.dropFirst()
236→
237→            let openFiles = rows.count
238→            let sockets = rows.filter { line in
239→                line.contains("TCP") || line.contains("UDP") || line.contains("IPv4") || line.contains("IPv6")
240→            }.count
241→
242→            let snapshot = ProcessInspectorSnapshot(openFiles: openFiles, sockets: sockets, inspectedAt: Date())
243→
244→            DispatchQueue.main.async {
245→                guard selectedProcessID == pid else { return }
246→                inspectorSnapshot = snapshot
247→                isInspectingSelectedProcess = false
248→            }
249→        }
250→    }
251→
252→    private func refreshSelectionIfNeeded() {
253→        guard let selectedProcessID else { return }
254→        guard let selected = monitor.current?.processes.first(where: { $0.id == selectedProcessID }) else {
255→            self.selectedProcessID = nil
256→            inspectorSnapshot = nil
257→            return
258→        }
259→
260→        if !isInspectingSelectedProcess {
261→            inspectProcess(selected)
262→        }
263→    }
264→
265→    private func scheduleSignalAction(for process: ProcessDetails, signal: Int32) {
266→        let (title, message, confirmTitle): (String, String, String)
267→        if signal == SIGKILL {
268→            title = "Force Quit Process?"
269→            message = "Force quit \(process.name) (PID \(process.id)) immediately?"
270→            confirmTitle = "Force Quit"
271→        } else {
272→            title = "Quit Process?"
273→            message = "Send a quit signal to \(process.name) (PID \(process.id))?"
274→            confirmTitle = "Quit"
275→        }
276→
277→        pendingSignalAction = PendingSignalAction(
278→            process: process,
279→            signal: signal,
280→            title: title,
281→            message: message,
282→            confirmTitle: confirmTitle
283→        )
284→    }
285→
286→    private func revealProcessInFinder(_ process: ProcessDetails) {
287→        guard let path = resolvedExecutablePaths[process.id] ?? ProcessMonitor.executablePath(for: process.id),
288→              !path.isEmpty else {
289→            return
290→        }
291→        resolvedExecutablePaths[process.id] = path
292→        let url = URL(fileURLWithPath: path)
293→        NSWorkspace.shared.activateFileViewerSelecting([url])
294→    }
295→
296→    private func executablePath(for process: ProcessDetails) -> String {
297→        if let resolved = resolvedExecutablePaths[process.id], !resolved.isEmpty {
298→            return resolved
299→        }
300→
301→        if !process.executablePath.isEmpty {
302→            return process.executablePath
303→        }
304→
305→        return "Path available when requested"
306→    }
307→
308→    private func abbreviatedPath(_ path: String) -> String {
309→        let home = FileManager.default.homeDirectoryForCurrentUser.path
310→        if path.hasPrefix(home) {
311→            return "~" + String(path.dropFirst(home.count))
312→        }
313→        return path
314→    }
315→
316→    private func inspectorValue(_ value: (ProcessInspectorSnapshot) -> String) -> String {
317→        if let snapshot = inspectorSnapshot {
318→            return value(snapshot)
319→        }
320→        return isInspectingSelectedProcess ? "..." : "-"
321→    }
322→
323→    private func formatBytes(_ bytes: UInt64) -> String {
324→        let formatter = ByteCountFormatter()
325→        formatter.countStyle = .memory
326→        formatter.allowedUnits = [.useMB, .useGB]
327→        return formatter.string(fromByteCount: Int64(bytes))
328→    }
329→}
330→
331→private struct ProcessRow: View {
332→    let process: ProcessDetails
333→    let isSelected: Bool
334→
335→    var body: some View {
336→        HStack(spacing: 8) {
337→            Text(process.name)
338→                .font(.system(size: 10, design: .monospaced))
339→                .foregroundColor(.primary)
340→                .lineLimit(1)
341→                .frame(width: 118, alignment: .leading)
342→
343→            Text("\(process.id)")
344→                .font(.system(size: 10, design: .monospaced))
345→                .foregroundColor(.secondary)
346→                .frame(width: 44, alignment: .leading)
347→
348→            Text(String(format: "%.1f", process.cpuUsage))
349→                .font(.system(size: 10, weight: .semibold, design: .monospaced))
350→                .foregroundColor(colorForCPU(process.cpuUsage))
351→                .frame(width: 54, alignment: .trailing)
352→
353→            Text(formatBytes(process.memoryUsage))
354→                .font(.system(size: 10, design: .monospaced))
355→                .foregroundColor(.secondary)
356→                .frame(width: 66, alignment: .trailing)
357→        }
358→        .padding(.horizontal, 8)
359→        .padding(.vertical, 4)
360→        .background(isSelected ? Color.blue.opacity(0.18) : Color.wtlCard.opacity(0.3))
361→        .cornerRadius(4)
362→    }
363→
364→    private func formatBytes(_ bytes: UInt64) -> String {
365→        let formatter = ByteCountFormatter()
366→        formatter.countStyle = .memory
367→        formatter.allowedUnits = [.useMB, .useGB]
368→        return formatter.string(fromByteCount: Int64(bytes))
369→    }
370→
371→    private func colorForCPU(_ usage: Double) -> Color {
372→        switch usage {
373→        case 0..<50: return .green
374→        case 50..<80: return .orange
375→        default: return .red
376→        }
377→    }
378→}
379→
380→private struct StatInline: View {
381→    let label: String
382→    let value: String
383→
384→    var body: some View {
385→        VStack(alignment: .leading, spacing: 2) {
386→            Text(label.uppercased())
387→                .font(.system(size: 8, weight: .medium, design: .monospaced))
388→                .foregroundColor(Color.wtlTertiary)
389→            Text(value)
390→                .font(.system(size: 10, weight: .semibold, design: .monospaced))
391→                .foregroundColor(Color.wtlSecondary)
392→        }
393→    }
