411→private func runCommand(_ executable: String, arguments: [String]) -> String? {
412→    let process = Process()
413→    let pipe = Pipe()
414→    let errorPipe = Pipe()
415→
416→    process.executableURL = URL(fileURLWithPath: executable)
417→    process.arguments = arguments
418→    process.standardOutput = pipe
419→    process.standardError = errorPipe
420→
421→    do {
422→        try process.run()
423→    } catch {
424→        return nil
425→    }
426→
427→    let data = pipe.fileHandleForReading.readDataToEndOfFile()
428→    process.waitUntilExit()
429→
430→    guard process.terminationStatus == 0 else { return nil }
431→    return String(data: data, encoding: .utf8)
432→}
