108→            switch battery.chargePercent {
109→            case 75...: symbolName = "battery.100"
110→            case 50..<75: symbolName = "battery.75"
111→            case 25..<50: symbolName = "battery.50"
112→            default: symbolName = "battery.25"
113→            }
114→        }
115→
116→        let config = NSImage.SymbolConfiguration(pointSize: 11, weight: .regular)
117→        let image = NSImage(systemSymbolName: symbolName, accessibilityDescription: nil)?
118→            .withSymbolConfiguration(config)
119→        image?.isTemplate = true
120→        return image
121→    }
122→}
