  1→import Foundation
  2→
  3→@Observable
  4→final class HistoryStore {
  5→    static let shared = HistoryStore()
  6→
  7→    var events: [TimelineEvent] = []
  8→    var snapshots: [MetricSnapshot] = []
  9→
 10→    private var snapshotTimer: Timer?
 11→    private weak var monitorCoordinator: MonitorCoordinator?
 12→    private let ioQueue = DispatchQueue(label: "WhatTheLoad.HistoryStore.IO", qos: .utility)
 13→    private let retentionInterval: TimeInterval = 7 * 24 * 60 * 60
 14→
 15→    private init() {
 16→        loadFromDisk()
 17→    }
 18→
 19→    func start(with coordinator: MonitorCoordinator) {
 20→        monitorCoordinator = coordinator
 21→        snapshotTimer?.invalidate()
 22→        snapshotTimer = Timer.scheduledTimer(withTimeInterval: 60, repeats: true) { [weak self] _ in
 23→            self?.recordSnapshotFromCurrentState()
 24→        }
 25→        recordSnapshotFromCurrentState()
 26→    }
 27→
 28→    func stop() {
 29→        snapshotTimer?.invalidate()
 30→        snapshotTimer = nil
 31→    }
 32→
 33→    func recordEvent(_ event: TimelineEvent) {
 34→        events.insert(event, at: 0)
 35→        pruneToRetentionWindow()
 36→        persistToDisk()
 37→    }
 38→
 39→    func events(in range: TimelineRange) -> [TimelineEvent] {
 40→        let cutoff = Date().addingTimeInterval(-range.duration)
 41→        return events.filter { $0.timestamp >= cutoff }
 42→    }
 43→
 44→    func snapshots(in range: TimelineRange) -> [MetricSnapshot] {
 45→        let cutoff = Date().addingTimeInterval(-range.duration)
 46→        return snapshots.filter { $0.timestamp >= cutoff }
 47→    }
 48→
 49→    private func recordSnapshotFromCurrentState() {
 50→        guard let coordinator = monitorCoordinator else { return }
 51→        guard
 52→            let cpu = coordinator.cpu.current,
 53→            let memory = coordinator.memory.current,
 54→            let network = coordinator.network.current,
 55→            let disk = coordinator.disk.current?.volumes.first
 56→        else {
 57→            return
 58→        }
 59→
 60→        let memoryUsedPercent = memory.total > 0
 61→            ? ((Double(memory.used + memory.wired) / Double(memory.total)) * 100)
 62→            : 0
 63→
 64→        let pressureScore: Double
 65→        switch memory.pressure {
 66→        case .normal: pressureScore = 0
 67→        case .warning: pressureScore = 50
 68→        case .critical: pressureScore = 100
 69→        }
 70→
 71→        let diskFreePercent = disk.total > 0 ? (Double(disk.free) / Double(disk.total)) * 100 : 0
 72→
 73→        let snapshot = MetricSnapshot(
 74→            cpuUsage: cpu.totalUsage,
 75→            memoryUsedPercent: memoryUsedPercent,
 76→            memoryPressureScore: pressureScore,
 77→            networkDownload: network.downloadSpeed,
 78→            networkUpload: network.uploadSpeed,
 79→            diskFreePercent: diskFreePercent,
 80→            batteryPercent: coordinator.battery.current?.chargePercent,
 81→            batteryIsCharging: coordinator.battery.current?.isCharging
 82→        )
 83→
 84→        snapshots.insert(snapshot, at: 0)
 85→        pruneToRetentionWindow()
 86→        persistToDisk()
 87→    }
 88→
 89→    private func pruneToRetentionWindow() {
 90→        let cutoff = Date().addingTimeInterval(-retentionInterval)
 91→        events.removeAll { $0.timestamp < cutoff }
 92→        snapshots.removeAll { $0.timestamp < cutoff }
 93→
 94→        if events.count > 5000 {
 95→            events = Array(events.prefix(5000))
 96→        }
 97→        if snapshots.count > 20000 {
 98→            snapshots = Array(snapshots.prefix(20000))
 99→        }
100→    }
101→
102→    private func persistenceDirectory() -> URL? {
103→        guard let appSupport = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask).first else {
104→            return nil
105→        }
106→        return appSupport.appendingPathComponent("WhatTheLoad", isDirectory: true)
107→    }
108→
109→    private func eventsURL() -> URL? {
110→        persistenceDirectory()?.appendingPathComponent("timeline_events.json")
111→    }
112→
113→    private func snapshotsURL() -> URL? {
114→        persistenceDirectory()?.appendingPathComponent("metric_snapshots.json")
115→    }
116→
117→    private func persistToDisk() {
118→        guard
119→            let directory = persistenceDirectory(),
120→            let eventsURL = eventsURL(),
121→            let snapshotsURL = snapshotsURL()
122→        else {
123→            return
124→        }
125→
126→        let eventsCopy = events
127→        let snapshotsCopy = snapshots
128→
129→        ioQueue.async {
130→            let fileManager = FileManager.default
131→            if !fileManager.fileExists(atPath: directory.path) {
132→                try? fileManager.createDirectory(at: directory, withIntermediateDirectories: true)
133→            }
134→
135→            let encoder = JSONEncoder()
136→            encoder.dateEncodingStrategy = .iso8601
137→            encoder.outputFormatting = [.prettyPrinted]
138→
139→            if let encodedEvents = try? encoder.encode(eventsCopy) {
140→                try? encodedEvents.write(to: eventsURL, options: .atomic)
141→            }
142→            if let encodedSnapshots = try? encoder.encode(snapshotsCopy) {
143→                try? encodedSnapshots.write(to: snapshotsURL, options: .atomic)
144→            }
145→        }
146→    }
147→
148→    private func loadFromDisk() {
149→        guard let eventsURL = eventsURL(), let snapshotsURL = snapshotsURL() else { return }
150→
151→        let decoder = JSONDecoder()
152→        decoder.dateDecodingStrategy = .iso8601
153→
154→        if let data = try? Data(contentsOf: eventsURL),
155→           let decoded = try? decoder.decode([TimelineEvent].self, from: data) {
156→            events = decoded
157→        }
158→
159→        if let data = try? Data(contentsOf: snapshotsURL),
160→           let decoded = try? decoder.decode([MetricSnapshot].self, from: data) {
161→            snapshots = decoded
162→        }
163→
164→        pruneToRetentionWindow()
165→    }
166→}
