118→        appendIcon(MenuBarItem.disk.symbolName, to: string)
119→        guard let volume = monitors.disk.current?.volumes.first, volume.total > 0 else {
120→            string.append(NSAttributedString(string: "–", attributes: baseAttributes))
121→            return
122→        }
123→        let usedPercent = Double(volume.used) / Double(volume.total) * 100
124→        string.append(NSAttributedString(
125→            string: String(format: "%.0f%%", usedPercent),
126→            attributes: baseAttributes
127→        ))
128→    }
129→
130→    private func appendBattery(to string: NSMutableAttributedString) {
131→        guard let battery = monitors.battery.current else { return }
132→
133→        if let batteryIcon = batteryImage(for: battery) {
134→            let attachment = NSTextAttachment()
135→            attachment.image = batteryIcon
136→            attachment.bounds = CGRect(x: 0, y: -2, width: 13, height: 13)
137→            string.append(NSAttributedString(attachment: attachment))
138→            string.append(NSAttributedString(string: " ", attributes: baseAttributes))
139→        }
140→
141→        if let timeText = batteryTimeText(for: battery) {
142→            string.append(NSAttributedString(string: timeText, attributes: baseAttributes))
143→        } else {
144→            string.append(NSAttributedString(
145→                string: String(format: "%.0f%%", battery.chargePercent),
146→                attributes: baseAttributes
147→            ))
148→        }
149→    }
