151→    // MARK: - Helpers
152→
153→    private func compactRate(_ bytesPerSecond: Double) -> String {
154→        let units = ["B/s", "K/s", "M/s", "G/s"]
155→        var value = max(bytesPerSecond, 0)
156→        var unitIndex = 0
157→
158→        while value >= 1000, unitIndex < units.count - 1 {
159→            value /= 1000
160→            unitIndex += 1
161→        }
162→
163→        let decimals: Int
164→        switch value {
165→        case 0..<10: decimals = 1
166→        case 10..<100: decimals = 1
167→        default: decimals = 0
168→        }
169→
170→        return String(format: "%.\(decimals)f%@", value, units[unitIndex])
171→    }
172→
173→    private func batteryTimeText(for battery: BatteryMetrics) -> String? {
174→        if let timeRemaining = battery.timeRemaining {
175→            return formatShortTime(timeRemaining)
176→        }
177→
178→        if battery.powerSource == .ac {
179→            return battery.chargePercent >= 99 ? "Full" : "AC"
180→        }
181→
182→        return nil
183→    }
184→
185→    private func formatShortTime(_ seconds: TimeInterval) -> String {
186→        let totalMinutes = Int(seconds / 60)
187→        let hours = totalMinutes / 60
188→        let minutes = totalMinutes % 60
189→        return String(format: "%d:%02d", hours, minutes)
190→    }
191→
192→    private func batteryImage(for battery: BatteryMetrics) -> NSImage? {
193→        let symbolName: String
194→
195→        if battery.isCharging {
196→            symbolName = "battery.100.bolt"
197→        } else {
198→            switch battery.chargePercent {
199→            case 75...: symbolName = "battery.100"
200→            case 50..<75: symbolName = "battery.75"
201→            case 25..<50: symbolName = "battery.50"
202→            default: symbolName = "battery.25"
203→            }
204→        }
205→
206→        let config = NSImage.SymbolConfiguration(pointSize: 11, weight: .regular)
207→        let image = NSImage(systemSymbolName: symbolName, accessibilityDescription: nil)?
208→            .withSymbolConfiguration(config)
209→        image?.isTemplate = true
210→        return image
211→    }
212→}
