142→        batteryAutomationTimer = Timer.scheduledTimer(withTimeInterval: 20.0, repeats: true) { [weak self] _ in
143→            self?.evaluateBatteryAutomation()
144→        }
145→        evaluateBatteryAutomation()
146→    }
