148→    private func checkLowBatteryAlert() {
149→        guard settings.lowBatteryAlertsEnabled else {
150→            lowBatteryAlertShown = false
151→            return
152→        }
153→
154→        guard let metrics = monitors.battery.current else { return }
155→
156→        let threshold = settings.lowBatteryAlertThreshold
157→        let isDischargingOnBattery = metrics.powerSource == .battery && !metrics.isCharging
158→
159→        if isDischargingOnBattery && metrics.chargePercent <= threshold {
160→            guard !lowBatteryAlertShown else { return }
161→            lowBatteryAlertShown = true
162→            if settings.alertPopupsEnabled {
163→                showLowBatteryAlert(metrics: metrics, threshold: threshold)
164→            }
165→            return
166→        }
167→
168→        let hasRecovered = metrics.isCharging || metrics.powerSource != .battery || metrics.chargePercent >= (threshold + 5)
169→        if hasRecovered {
170→            lowBatteryAlertShown = false
171→        }
172→    }
173→
174→    private func evaluateBatteryAutomation() {
175→        guard settings.batteryAutomationEnabled else {
176→            if settings.powerSaveModeActive {
177→                setPowerSaveMode(false, reason: "Low battery automation disabled.")
178→            }
179→            return
180→        }
181→
182→        guard let metrics = monitors.battery.current else { return }
183→        let threshold = settings.batteryAutomationThreshold
184→
185→        let shouldEnable = metrics.powerSource == .battery &&
186→            !metrics.isCharging &&
187→            metrics.chargePercent <= threshold
188→        let shouldDisable = metrics.isCharging ||
189→            metrics.powerSource != .battery ||
190→            metrics.chargePercent >= (threshold + 5)
191→
192→        if shouldEnable && !settings.powerSaveModeActive {
193→            setPowerSaveMode(true, reason: String(format: "Battery reached %.0f%%.", metrics.chargePercent))
194→            if settings.batteryAutomationAutoOpenSettings {
195→                openBatterySettingsIfNeeded()
196→            }
197→        } else if shouldDisable && settings.powerSaveModeActive {
198→            setPowerSaveMode(false, reason: "Battery state recovered.")
199→        }
200→    }
201→
202→    private func setPowerSaveMode(_ enabled: Bool, reason: String) {
203→        settings.powerSaveModeActive = enabled
204→        monitors.setPowerSaveMode(enabled)
205→        historyStore.recordEvent(TimelineEvent(
206→            severity: .info,
207→            category: .battery,
208→            title: enabled ? "Power Save Mode Enabled" : "Power Save Mode Disabled",
209→            message: reason
210→        ))
211→    }
212→
213→    private func openBatterySettingsIfNeeded() {
214→        let now = Date()
215→        if let lastOpened = batterySettingsOpenedAt, now.timeIntervalSince(lastOpened) < 1800 {
216→            return
217→        }
218→        batterySettingsOpenedAt = now
219→
220→        let urls = [
221→            "x-apple.systempreferences:com.apple.preference.battery",
222→            "x-apple.systempreferences:com.apple.Battery-Settings.extension"
223→        ]
224→
225→        for rawURL in urls {
226→            guard let url = URL(string: rawURL) else { continue }
227→            if NSWorkspace.shared.open(url) {
228→                return
229→            }
230→        }
231→    }
232→
233→    private func showLowBatteryAlert(metrics: BatteryMetrics, threshold: Double) {
234→        let levelText = String(format: "%.0f", metrics.chargePercent)
235→        let thresholdText = String(format: "%.0f", threshold)
236→
237→        var details = "Battery level is \(levelText)% (threshold \(thresholdText)%)."
238→        if let remaining = metrics.timeRemaining {
239→            details += "\nEstimated time remaining: \(formatRemainingTime(remaining))."
240→        }
241→        details += "\nPlug in your charger soon."
242→
243→        NSApp.activate(ignoringOtherApps: true)
244→
245→        let alert = NSAlert()
246→        alert.alertStyle = .warning
247→        alert.messageText = "Low Battery"
248→        alert.informativeText = details
249→        alert.addButton(withTitle: "Dismiss")
250→        alert.runModal()
251→    }
252→
253→    private func showBlockingAlert(severity: TimelineSeverity, title: String, message: String) {
254→        DispatchQueue.main.async {
255→            NSApp.activate(ignoringOtherApps: true)
256→
257→            let alert = NSAlert()
258→            alert.alertStyle = (severity == .critical) ? .critical : .warning
259→            alert.messageText = title
260→            alert.informativeText = message
261→            alert.addButton(withTitle: "Dismiss")
262→            alert.runModal()
263→        }
264→    }
265→
266→    private func formatRemainingTime(_ seconds: TimeInterval) -> String {
267→        let totalMinutes = max(0, Int(seconds / 60))
268→        let hours = totalMinutes / 60
269→        let minutes = totalMinutes % 60
270→
271→        if hours > 0 {
272→            return "\(hours)h \(minutes)m"
273→        }
274→        return "\(minutes)m"
275→    }
276→}
