  1→import Foundation
  2→import Network
  3→
  4→class PingEngine {
  5→    private var connection: NWConnection?
  6→    private let host: String
  7→    private let port: UInt16
  8→    private let queue = DispatchQueue(label: "wtl.pingengine", qos: .background)
  9→    private var isRunning = false
 10→    private var reconnectScheduled = false
 11→
 12→    private var measurements: [Double] = []
 13→    private let maxSamples = 30
 14→    private var attempts = 0
 15→    private var failures = 0
 16→
 17→    var currentPing: Double? {
 18→        measurements.last
 19→    }
 20→
 21→    var averagePing: Double? {
 22→        guard !measurements.isEmpty else { return nil }
 23→        return measurements.reduce(0, +) / Double(measurements.count)
 24→    }
 25→
 26→    var jitter: Double? {
 27→        guard measurements.count > 1 else { return nil }
 28→
 29→        var deltas: [Double] = []
 30→        for i in 1..<measurements.count {
 31→            deltas.append(abs(measurements[i] - measurements[i-1]))
 32→        }
 33→
 34→        return deltas.reduce(0, +) / Double(deltas.count)
 35→    }
 36→
 37→    var packetLoss: Double = 0
 38→
 39→    init(host: String, port: UInt16 = 80) {
 40→        self.host = host
 41→        self.port = port
 42→    }
 43→
 44→    func start() {
 45→        isRunning = true
 46→        reconnectScheduled = false
 47→        startConnection()
 48→    }
 49→
 50→    func stop() {
 51→        isRunning = false
 52→        reconnectScheduled = false
 53→        connection?.cancel()
 54→        connection = nil
 55→    }
 56→
 57→    private func startConnection() {
 58→        guard isRunning else { return }
 59→
 60→        let endpoint = NWEndpoint.hostPort(host: NWEndpoint.Host(host), port: NWEndpoint.Port(integerLiteral: port))
 61→        let newConnection = NWConnection(to: endpoint, using: .tcp)
 62→        connection = newConnection
 63→
 64→        newConnection.stateUpdateHandler = { [weak self, weak newConnection] state in
 65→            guard let self, let connection = newConnection else { return }
 66→
 67→            switch state {
 68→            case .ready:
 69→                self.sendPing(on: connection)
 70→            case .failed:
 71→                self.recordFailure()
 72→                self.scheduleReconnect()
 73→            case .cancelled:
 74→                break
 75→            default:
 76→                break
 77→            }
 78→        }
 79→
 80→        newConnection.start(queue: queue)
 81→    }
 82→
 83→    private func sendPing(on connection: NWConnection) {
 84→        let start = Date()
 85→        attempts += 1
 86→
 87→        connection.send(content: Data([0x00]), completion: .contentProcessed { [weak self, weak connection] error in
 88→            guard let self else { return }
 89→            let latency = Date().timeIntervalSince(start) * 1000 // ms
 90→
 91→            if error == nil {
 92→                self.recordSuccess(latency: latency)
 93→            } else {
 94→                self.recordFailure()
 95→            }
 96→
 97→            connection?.cancel()
 98→            self.scheduleReconnect()
 99→        })
100→    }
101→
102→    private func scheduleReconnect() {
103→        guard isRunning, !reconnectScheduled else { return }
104→        reconnectScheduled = true
105→
106→        queue.asyncAfter(deadline: .now() + 1.0) { [weak self] in
107→            guard let self else { return }
108→            self.reconnectScheduled = false
109→            guard self.isRunning else { return }
110→            self.connection?.cancel()
111→            self.connection = nil
112→            self.startConnection()
113→        }
114→    }
115→
116→    private func recordSuccess(latency: Double) {
117→        measurements.append(latency)
118→        if measurements.count > maxSamples {
119→            measurements.removeFirst()
120→        }
121→
122→        // Decay packet loss after successful samples
123→        packetLoss = calculatedPacketLoss()
124→    }
125→
126→    private func recordFailure() {
127→        failures += 1
128→        packetLoss = calculatedPacketLoss()
129→    }
130→
131→    private func calculatedPacketLoss() -> Double {
132→        guard attempts > 0 else { return 0 }
133→        return min(max((Double(failures) / Double(attempts)) * 100.0, 0), 100)
134→    }
135→}
