import Foundation

@Observable
final class HistoryStore {
    static let shared = HistoryStore()

    var events: [TimelineEvent] = []
    var snapshots: [MetricSnapshot] = []

    private var snapshotTimer: Timer?
    private weak var monitorCoordinator: MonitorCoordinator?
    private let ioQueue = DispatchQueue(label: "WhatTheLoad.HistoryStore.IO", qos: .utility)
    private let retentionInterval: TimeInterval = 7 * 24 * 60 * 60

    private init() {
        loadFromDisk()
    }

    func start(with coordinator: MonitorCoordinator) {
        monitorCoordinator = coordinator
        snapshotTimer?.invalidate()
        snapshotTimer = Timer.scheduledTimer(withTimeInterval: 60, repeats: true) { [weak self] _ in
            self?.recordSnapshotFromCurrentState()
        }
        recordSnapshotFromCurrentState()
    }

    func stop() {
        snapshotTimer?.invalidate()
        snapshotTimer = nil
    }

    func recordEvent(_ event: TimelineEvent) {
        events.insert(event, at: 0)
        pruneToRetentionWindow()
        persistToDisk()
    }

    func events(in range: TimelineRange) -> [TimelineEvent] {
        let cutoff = Date().addingTimeInterval(-range.duration)
        return events.filter { $0.timestamp >= cutoff }
    }

    func snapshots(in range: TimelineRange) -> [MetricSnapshot] {
        let cutoff = Date().addingTimeInterval(-range.duration)
        return snapshots.filter { $0.timestamp >= cutoff }
    }

    private func recordSnapshotFromCurrentState() {
        guard let coordinator = monitorCoordinator else { return }
        guard
            let cpu = coordinator.cpu.current,
            let memory = coordinator.memory.current,
            let network = coordinator.network.current,
            let disk = coordinator.disk.current?.volumes.first
        else {
            return
        }

        let memoryUsedPercent = memory.total > 0
            ? ((Double(memory.used + memory.wired) / Double(memory.total)) * 100)
            : 0

        let pressureScore: Double
        switch memory.pressure {
        case .normal: pressureScore = 0
        case .warning: pressureScore = 50
        case .critical: pressureScore = 100
        }

        let diskFreePercent = disk.total > 0 ? (Double(disk.free) / Double(disk.total)) * 100 : 0

        let snapshot = MetricSnapshot(
            cpuUsage: cpu.totalUsage,
            memoryUsedPercent: memoryUsedPercent,
            memoryPressureScore: pressureScore,
            networkDownload: network.downloadSpeed,
            networkUpload: network.uploadSpeed,
            diskFreePercent: diskFreePercent,
            batteryPercent: coordinator.battery.current?.chargePercent,
            batteryIsCharging: coordinator.battery.current?.isCharging
        )

        snapshots.insert(snapshot, at: 0)
        pruneToRetentionWindow()
        persistToDisk()
    }

    private func pruneToRetentionWindow() {
        let cutoff = Date().addingTimeInterval(-retentionInterval)
        events.removeAll { $0.timestamp < cutoff }
        snapshots.removeAll { $0.timestamp < cutoff }

        if events.count > 5000 {
            events = Array(events.prefix(5000))
        }
        if snapshots.count > 20000 {
            snapshots = Array(snapshots.prefix(20000))
        }
    }

    private func persistenceDirectory() -> URL? {
        guard let appSupport = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask).first else {
            return nil
        }
        return appSupport.appendingPathComponent("WhatTheLoad", isDirectory: true)
    }

    private func eventsURL() -> URL? {
        persistenceDirectory()?.appendingPathComponent("timeline_events.json")
    }

    private func snapshotsURL() -> URL? {
        persistenceDirectory()?.appendingPathComponent("metric_snapshots.json")
    }

    private func persistToDisk() {
        guard
            let directory = persistenceDirectory(),
            let eventsURL = eventsURL(),
            let snapshotsURL = snapshotsURL()
        else {
            return
        }

        let eventsCopy = events
        let snapshotsCopy = snapshots

        ioQueue.async {
            let fileManager = FileManager.default
            if !fileManager.fileExists(atPath: directory.path) {
                try? fileManager.createDirectory(at: directory, withIntermediateDirectories: true)
            }

            let encoder = JSONEncoder()
            encoder.dateEncodingStrategy = .iso8601
            encoder.outputFormatting = [.prettyPrinted]

            if let encodedEvents = try? encoder.encode(eventsCopy) {
                try? encodedEvents.write(to: eventsURL, options: .atomic)
            }
            if let encodedSnapshots = try? encoder.encode(snapshotsCopy) {
                try? encodedSnapshots.write(to: snapshotsURL, options: .atomic)
            }
        }
    }

    private func loadFromDisk() {
        guard let eventsURL = eventsURL(), let snapshotsURL = snapshotsURL() else { return }

        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601

        if let data = try? Data(contentsOf: eventsURL),
           let decoded = try? decoder.decode([TimelineEvent].self, from: data) {
            events = decoded
        }

        if let data = try? Data(contentsOf: snapshotsURL),
           let decoded = try? decoder.decode([MetricSnapshot].self, from: data) {
            snapshots = decoded
        }

        pruneToRetentionWindow()
    }
}

import Foundation

@Observable
class MemoryMonitor {
    var current: MemoryMetrics?
    var history: [MemoryMetrics] = []

    private var timer: Timer?

    func start(interval: TimeInterval = 2.0) {
        timer?.invalidate()
        timer = Timer.scheduledTimer(withTimeInterval: interval, repeats: true) { [weak self] _ in
            self?.update()
        }
        update()
    }

    func stop() {
        timer?.invalidate()
        timer = nil
    }

    private func update() {
        guard let metrics = fetchMetrics() else { return }

        current = metrics
        history.append(metrics)

        if history.count > 120 {
            history.removeFirst()
        }
    }

    private func fetchMetrics() -> MemoryMetrics? {
        var stats = vm_statistics64()
        var count = mach_msg_type_number_t(MemoryLayout<vm_statistics64>.stride / MemoryLayout<integer_t>.stride)

        let result = withUnsafeMutablePointer(to: &stats) {
            $0.withMemoryRebound(to: integer_t.self, capacity: Int(count)) { pointer in
                host_statistics64(mach_host_self(), HOST_VM_INFO64, pointer, &count)
            }
        }

        guard result == KERN_SUCCESS else { return nil }

        let pageSize = UInt64(vm_kernel_page_size)
        let active = UInt64(stats.active_count) * pageSize
        let inactive = UInt64(stats.inactive_count) * pageSize
        let wired = UInt64(stats.wire_count) * pageSize
        let compressed = UInt64(stats.compressor_page_count) * pageSize
        let free = UInt64(stats.free_count) * pageSize

        let used = active + inactive

        var size: UInt64 = 0
        var sizeLength = MemoryLayout<UInt64>.size
        sysctlbyname("hw.memsize", &size, &sizeLength, nil, 0)

        let pressure: MemoryPressure
        let usedPercentage = Double(used + wired) / Double(size)
        if usedPercentage > 0.9 {
            pressure = .critical
        } else if usedPercentage > 0.7 {
            pressure = .warning
        } else {
            pressure = .normal
        }

        return MemoryMetrics(
            timestamp: Date(),
            used: used,
            wired: wired,
            compressed: compressed,
            free: free,
            total: size,
            pressure: pressure,
            swapUsed: UInt64(stats.swapins) * pageSize,
            swapTotal: UInt64(stats.swapins + stats.swapouts) * pageSize
        )
    }
}

import Foundation

@Observable
class ProcessMonitor {
    var current: ProcessMetrics?
    var history: [ProcessMetrics] = []

    private var timer: Timer?
    private var previousCPUTimesByPID: [pid_t: UInt64] = [:]
    private var previousSampleTimestamp: Date?

    func start(interval: TimeInterval = 3.0) {
        timer?.invalidate()
        timer = Timer.scheduledTimer(withTimeInterval: interval, repeats: true) { [weak self] _ in
            self?.update()
        }
        update()
    }

    func stop() {
        timer?.invalidate()
        timer = nil
    }

    private func update() {
        guard let metrics = fetchMetrics() else { return }

        current = metrics
        history.append(metrics)

        if history.count > 120 {
            history.removeFirst()
        }
    }

    private func fetchMetrics() -> ProcessMetrics? {
        let sampleTime = Date()
        let elapsed = previousSampleTimestamp.map { sampleTime.timeIntervalSince($0) } ?? 0
        let maxCPUPercent = Double(ProcessInfo.processInfo.activeProcessorCount) * 100.0
        var currentCPUTimesByPID: [pid_t: UInt64] = [:]

        var pids = [pid_t](repeating: 0, count: 1024)
        let count = proc_listallpids(&pids, Int32(pids.count * MemoryLayout<pid_t>.size))

        guard count > 0 else { return nil }

        let actualCount = Int(count) / MemoryLayout<pid_t>.size
        let processes = pids.prefix(actualCount).compactMap { pid -> ProcessDetails? in
            guard pid > 0 else { return nil }

            var info = proc_taskinfo()
            let size = MemoryLayout<proc_taskinfo>.size
            let result = proc_pidinfo(pid, PROC_PIDTASKINFO, 0, &info, Int32(size))

            guard result == Int32(size) else { return nil }

            let name = processName(for: pid)

            let memoryUsage = info.pti_resident_size
            let totalCPUTime = UInt64(info.pti_total_user + info.pti_total_system)
            currentCPUTimesByPID[pid] = totalCPUTime

            // Only include processes with significant memory usage
            guard memoryUsage > 1_000_000 else { return nil } // > 1MB

            let cpuUsage: Double
            if elapsed > 0, let previousCPUTime = previousCPUTimesByPID[pid], totalCPUTime >= previousCPUTime {
                let deltaCPUTime = totalCPUTime - previousCPUTime
                let deltaSeconds = Double(deltaCPUTime) / 1_000_000_000.0 // proc_taskinfo time is ns
                cpuUsage = min(max((deltaSeconds / elapsed) * 100.0, 0), maxCPUPercent)
            } else {
                cpuUsage = 0
            }

            return ProcessDetails(
                id: pid,
                name: name,
                executablePath: "",
                cpuUsage: cpuUsage,
                memoryUsage: memoryUsage,
                state: .running
            )
        }

        // Keep a useful working set for both memory and CPU-oriented views.
        let topByMemory = processes.sorted { $0.memoryUsage > $1.memoryUsage }.prefix(60)
        let topByCPU = processes.sorted { $0.cpuUsage > $1.cpuUsage }.prefix(60)

        var seen = Set<pid_t>()
        var topProcesses: [ProcessDetails] = []
        for process in Array(topByCPU) + Array(topByMemory) {
            if seen.insert(process.id).inserted {
                topProcesses.append(process)
            }
            if topProcesses.count >= 100 {
                break
            }
        }

        previousCPUTimesByPID = currentCPUTimesByPID
        previousSampleTimestamp = sampleTime

        return ProcessMetrics(
            timestamp: sampleTime,
            processes: topProcesses
        )
    }

    private func processName(for pid: pid_t) -> String {
        var nameBuffer = [CChar](repeating: 0, count: Int(MAXPATHLEN))
        let result = proc_name(pid, &nameBuffer, UInt32(nameBuffer.count))
        guard result > 0 else { return "Unknown" }
        return String(cString: nameBuffer)
    }

    static func executablePath(for pid: pid_t) -> String? {
        var pathBuffer = [CChar](repeating: 0, count: Int(MAXPATHLEN))
        let result = proc_pidpath(pid, &pathBuffer, UInt32(pathBuffer.count))
        guard result > 0 else { return nil }
        return String(cString: pathBuffer)
    }
}

import Foundation

@Observable
class CPUMonitor {
    var current: CPUMetrics?
    var history: [CPUMetrics] = []

    private var timer: Timer?
    private var previousInfo: host_cpu_load_info_data_t?
    private var previousPerCoreTicks: [CPUTicks] = []
    private var smcReader: SMCReader?

    private struct CPUTicks {
        let user: Int64
        let system: Int64
        let idle: Int64
        let nice: Int64
    }

    func start(interval: TimeInterval = 1.0) {
        smcReader = SMCReader()
        timer?.invalidate()
        previousInfo = nil
        previousPerCoreTicks = []
        timer = Timer.scheduledTimer(withTimeInterval: interval, repeats: true) { [weak self] _ in
            self?.update()
        }
        update()
    }

    func stop() {
        timer?.invalidate()
        timer = nil
    }

    private func update() {
        guard let metrics = fetchMetrics() else { return }

        current = metrics
        history.append(metrics)

        if history.count > 120 {
            history.removeFirst()
        }
    }

    private func fetchMetrics() -> CPUMetrics? {
        var cpuLoad = host_cpu_load_info()
        var count = mach_msg_type_number_t(MemoryLayout<host_cpu_load_info>.stride / MemoryLayout<integer_t>.stride)

        let result = withUnsafeMutablePointer(to: &cpuLoad) {
            $0.withMemoryRebound(to: integer_t.self, capacity: Int(count)) { pointer in
                host_statistics(mach_host_self(), HOST_CPU_LOAD_INFO, pointer, &count)
            }
        }

        guard result == KERN_SUCCESS else { return nil }

        let userTime = Int64(cpuLoad.cpu_ticks.0)
        let systemTime = Int64(cpuLoad.cpu_ticks.1)
        let idleTime = Int64(cpuLoad.cpu_ticks.2)
        let niceTime = Int64(cpuLoad.cpu_ticks.3)
        let currentTicks = CPUTicks(user: userTime, system: systemTime, idle: idleTime, nice: niceTime)
        let totalUsage: Double

        if let previousInfo {
            let previousTicks = CPUTicks(
                user: Int64(previousInfo.cpu_ticks.0),
                system: Int64(previousInfo.cpu_ticks.1),
                idle: Int64(previousInfo.cpu_ticks.2),
                nice: Int64(previousInfo.cpu_ticks.3)
            )
            totalUsage = usagePercentage(from: previousTicks, to: currentTicks)
        } else {
            totalUsage = 0
        }
        previousInfo = cpuLoad

        let measuredPerCoreUsage = fetchPerCoreUsage()
        let hasPerCoreSignal = measuredPerCoreUsage.contains { $0 > 0.05 }
        let perCoreUsage = hasPerCoreSignal
            ? measuredPerCoreUsage
            : fallbackPerCoreUsage(totalUsage: totalUsage)
        let resolvedTotalUsage = perCoreUsage.isEmpty
            ? totalUsage
            : (perCoreUsage.reduce(0, +) / Double(perCoreUsage.count))

        return CPUMetrics(
            timestamp: Date(),
            totalUsage: min(max(resolvedTotalUsage, 0), 100),
            perCoreUsage: perCoreUsage,
            temperature: fetchTemperature(),
            frequency: fetchFrequency(),
            isThrottled: false
        )
    }

    private func fetchPerCoreUsage() -> [Double] {
        var cpuInfo: processor_info_array_t?
        var cpuInfoCount: mach_msg_type_number_t = 0
        var cpuCount: natural_t = 0

        let result = host_processor_info(
            mach_host_self(),
            PROCESSOR_CPU_LOAD_INFO,
            &cpuCount,
            &cpuInfo,
            &cpuInfoCount
        )

        guard result == KERN_SUCCESS, let cpuInfo else {
            return previousPerCoreTicks.map { _ in 0 }
        }

        let cpuStateCount = Int(CPU_STATE_MAX)
        var currentPerCoreTicks: [CPUTicks] = []
        currentPerCoreTicks.reserveCapacity(Int(cpuCount))

        for core in 0..<Int(cpuCount) {
            let base = core * cpuStateCount
            let user = Int64(cpuInfo[base + Int(CPU_STATE_USER)])
            let system = Int64(cpuInfo[base + Int(CPU_STATE_SYSTEM)])
            let idle = Int64(cpuInfo[base + Int(CPU_STATE_IDLE)])
            let nice = Int64(cpuInfo[base + Int(CPU_STATE_NICE)])
            currentPerCoreTicks.append(CPUTicks(user: user, system: system, idle: idle, nice: nice))
        }

        let deallocateSize = vm_size_t(Int(cpuInfoCount) * MemoryLayout<integer_t>.stride)
        vm_deallocate(mach_task_self_, vm_address_t(bitPattern: cpuInfo), deallocateSize)

        guard previousPerCoreTicks.count == currentPerCoreTicks.count else {
            previousPerCoreTicks = currentPerCoreTicks
            return currentPerCoreTicks.map { _ in 0 }
        }

        let usages = zip(previousPerCoreTicks, currentPerCoreTicks).map { previousTicks, currentTicks in
            usagePercentage(from: previousTicks, to: currentTicks)
        }
        previousPerCoreTicks = currentPerCoreTicks
        return usages
    }

    private func usagePercentage(from previous: CPUTicks, to current: CPUTicks) -> Double {
        let userDelta = safeDelta(current.user, previous.user)
        let systemDelta = safeDelta(current.system, previous.system)
        let idleDelta = safeDelta(current.idle, previous.idle)
        let niceDelta = safeDelta(current.nice, previous.nice)

        let totalDelta = userDelta + systemDelta + idleDelta + niceDelta
        guard totalDelta > 0 else { return 0 }

        let usedDelta = userDelta + systemDelta + niceDelta
        return (Double(usedDelta) / Double(totalDelta)) * 100.0
    }

    private func safeDelta(_ current: Int64, _ previous: Int64) -> UInt64 {
        guard current >= previous else {
            return UInt64(max(current, 0))
        }
        return UInt64(current - previous)
    }

    private func fetchTemperature() -> Double? {
        return smcReader?.getCPUTemperature()
    }

    private func fetchFrequency() -> Double? {
        // Would use sysctl to get current CPU frequency
        return 3.2
    }

    private func fallbackPerCoreUsage(totalUsage: Double) -> [Double] {
        let coreCount = max(ProcessInfo.processInfo.activeProcessorCount, 1)
        let clamped = min(max(totalUsage, 0), 100)
        return Array(repeating: clamped, count: coreCount)
    }
}

