        if let channel = interface.wlanChannel() {
            switch channel.channelBand {
            case .band2GHz: band = .band2_4GHz
            case .band5GHz: band = .band5GHz
            case .band6GHz: band = .band6GHz
            default: band = nil
            }
        } else {
            band = nil
        }

