            DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) { [weak self] in
                guard let self else { return }
                if self.locationAuthorizationStatus == .notDetermined {
                    self.openLocationPrivacySettings()
                    self.update()
                }
            }
        }
    }

