        let units = ["B/s", "K/s", "M/s", "G/s"]
        var value = max(bytesPerSecond, 0)
        var unitIndex = 0

        while value >= 1000, unitIndex < units.count - 1 {
            value /= 1000
            unitIndex += 1
        }

        let decimals: Int
        switch value {
        case 0..<10: decimals = 1
        case 10..<100: decimals = 1
